package com.example.samlsp;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.io.Resource;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.provisioning.InMemoryUserDetailsManager;
import org.springframework.security.saml2.core.Saml2X509Credential;
import org.springframework.security.saml2.provider.service.metadata.OpenSamlMetadataResolver;
import org.springframework.security.saml2.provider.service.registration.InMemoryRelyingPartyRegistrationRepository;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistration;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistrationRepository;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistrations;
import org.springframework.security.saml2.provider.service.web.Saml2MetadataFilter;
import org.springframework.security.saml2.provider.service.web.authentication.Saml2WebSsoAuthenticationFilter;
import org.springframework.security.web.SecurityFilterChain;

import java.io.IOException;
import java.security.KeyStore;
import java.security.KeyStoreException;
import java.security.NoSuchAlgorithmException;
import java.security.PrivateKey;
import java.security.UnrecoverableKeyException;
import java.security.cert.CertificateException;
import java.security.cert.X509Certificate;

import static org.springframework.security.saml2.core.Saml2X509Credential.Saml2X509CredentialType.DECRYPTION;
import static org.springframework.security.saml2.core.Saml2X509Credential.Saml2X509CredentialType.SIGNING;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Value("classpath:saml-sp.p12")
    private Resource keystoreResource;

    @Value("${app.saml.keystore.password}")
    private String keystorePassword;

    @Value("${app.saml.keystore.alias}")
    private String keystoreAlias;

    @Value("${app.saml.private-key.password}")
    private String privateKeyPassword;

    @Value("classpath:idp-metadata.xml")
    private Resource idpMetadataResource;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http, RelyingPartyRegistrationRepository relyingPartyRegistrationRepository) throws Exception {
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/", "/error", "/saml2/authenticate/**", "/saml2/service-provider-metadata/**").permitAll()
                .anyRequest().authenticated()
            )
            .saml2Login(saml2Login -> saml2Login
                .relyingPartyRegistrationRepository(relyingPartyRegistrationRepository)
                // Optional: Customize the SAML 2.0 login endpoint
                // .loginProcessingUrl("/saml2/authenticate/{registrationId}")
            )
            .saml2Logout(saml2Logout -> saml2Logout
                    // Configure SAML 2.0 Logout here if needed (e.g., global logout)
                    // .logoutUrl("/saml2/logout/{registrationId}")
                    // .logoutSuccessUrl("/")
            )
            .csrf(csrf -> csrf.disable()); // For simplicity in demo, disable CSRF. Re-enable and configure for production.

        // Generate SP metadata automatically at /saml2/service-provider-metadata/{registrationId}
        Saml2MetadataFilter metadataFilter = new Saml2MetadataFilter(
                relyingPartyRegistrationRepository, new OpenSamlMetadataResolver());
        http.addFilterBefore(metadataFilter, Saml2WebSsoAuthenticationFilter.class);

        return http.build();
    }

    @Bean
    public RelyingPartyRegistrationRepository relyingPartyRegistrationRepository() {
        RelyingPartyRegistration registration = null;
        try {
            // Load SP Key Pair
            KeyStore keyStore = KeyStore.getInstance("PKCS12");
            keyStore.load(keystoreResource.getInputStream(), keystorePassword.toCharArray());

            PrivateKey privateKey = (PrivateKey) keyStore.getKey(keystoreAlias, privateKeyPassword.toCharArray());
            X509Certificate certificate = (X509Certificate) keyStore.getCertificate(keystoreAlias);

            Saml2X509Credential signingCredential = new Saml2X509Credential(privateKey, certificate, SIGNING);
            Saml2X509Credential decryptionCredential = new Saml2X509Credential(privateKey, certificate, DECRYPTION);

            // Build RelyingPartyRegistration using IdP metadata
            registration = RelyingPartyRegistrations
                    .fromMetadata(idpMetadataResource.getInputStream().readAllBytes())
                    .registrationId("my-saml-sp") // Unique ID for this SP registration (used in URL paths)
                    .entityId("http://localhost:8080/saml2/service-provider-metadata/my-saml-sp") // SP Entity ID
                    .assertionConsumerServiceLocation("http://localhost:8080/saml2/authenticate/my-saml-sp") // ACS URL
                    .singleLogoutServiceLocation("http://localhost:8080/saml2/logout/my-saml-sp") // SLO URL (optional)
                    .signingX509Credentials(c -> c.add(signingCredential))
                    .decryptionX509Credentials(c -> c.add(decryptionCredential))
                    .build();

        } catch (KeyStoreException | IOException | NoSuchAlgorithmException | CertificateException | UnrecoverableKeyException e) {
            throw new RuntimeException("Failed to load SAML keystore or IdP metadata", e);
        }

        return new InMemoryRelyingPartyRegistrationRepository(registration);
    }

    // This UserDetailsService is for traditional Spring Security form login, not directly used by SAML.
    // SAML authentication produces a Saml2AuthenticatedPrincipal.
    // If you need to map SAML attributes to your internal User model and roles, you'd configure a custom
    // Saml2AuthenticatedPrincipalConverter or an AuthenticationUserDetailsService for Saml2AuthenticationToken.
    @Bean
    public UserDetailsService userDetailsService() {
        UserDetails user = User.withUsername("defaultuser")
                .password("{noop}password") // {noop} for plain text password, not recommended for prod
                .roles("USER")
                .build();
        return new InMemoryUserDetailsManager(user);
    }
}
